# ---------- STATS ----------
def show_stats(cur):
    tables=["departments","positions","employees","salary_history","attendance","vacations","performance_reviews","trainings","training_participants","projects","project_members","tasks","task_comments","task_dependencies","time_logs","budgets","expenses","invoices","payments","contracts","clients","client_contacts","products","deals","orders","order_items","suppliers","inventory","assets","shipments","meetings","meeting_participants","notifications","audit_log"]
    for t in tables:
        cur.execute(sql.SQL("SELECT COUNT(*) FROM {}").format(sql.Identifier(t)))
        print(f"  {t}: {cur.fetchone()[0]} recs")

# ---------- MAIN ----------
def main():
    p=argparse.ArgumentParser(description="NL2SQL PostgreSQL test DB (34 tables)")
    p.add_argument("--host",default="localhost")
    p.add_argument("--port",type=int,default=5432)
    p.add_argument("--dbname",default="nl2sql_test")
    p.add_argument("--user",default="postgres")
    p.add_argument("--password",default="")
    p.add_argument("--skip-db",action="store_true")
    a=p.parse_args()
    print(f"=== NL2SQL PostgreSQL Init (34 tables) ===")
    print(f"Host: {a.host}:{a.port} DB: {a.dbname} User: {a.user}")
    if not a.skip_db and not mkdb(a):sys.exit(1)
    c=conn(a,a.dbname);c.autocommit=1;cur=c.cursor()
    print("\n[1/2] Creating tables...")
    create_tables(cur)
    print("\n[2/2] Loading data...")
    fill_data(cur)
    print("\n=== STATS ===")
    show_stats(cur)
    cur.close();c.close()
    print(f"\n=== DONE ===")
    print(f"Connect: postgresql://{a.user}@{a.host}:{a.port}/{a.dbname}")
    print(f"On site: tab \"Server\" -> PostgreSQL -> fill form -> Connect")

if __name__=="__main__":main()

